// The ALLERGEN CROSS-REACTIVITY dataset, loaded onto the curated-dataset framework
// (issue #860 Track B). Copies the food-drug-interactions.ts shape: import the envelope
// JSON (generated by scripts/gen-allergen-cross-reactivity.ts), validate it once with
// loadDataset(), and expose the family ENTRIES the matcher consumes. Identity is the
// stable slug `id` (fieldStrategy) — one entry per id, so the harness's identity-resolves
// / refusal-gate hold. The registry lists this for the linter; lib/allergen-cross-
// reactivity.ts is the DOMAIN matcher (it resolves a profile's allergens to families by
// member/alias form-overlap, which is domain logic, not the family's slug identity).
// SAFETY-critical — it backs the #691 allergy safety belt. Pure — no DB, no network.

import rawFamilies from "./data/allergen-cross-reactivity.json";
import { loadDataset } from "./loader";
import { fieldStrategy } from "./matcher";
import type { CrossReactivityFamily } from "@/scripts/gen-allergen-cross-reactivity";

export type { CrossReactivityFamily } from "@/scripts/gen-allergen-cross-reactivity";

// The validated dataset (envelope + guarantees). Throws at module load if the committed
// JSON ever violates the contract — a loud, early failure.
export const allergenCrossReactivityDataset =
  loadDataset<CrossReactivityFamily>(rawFamilies);

// Identity strategy: the stable slug `id` (case-folded). For the linter/harness — each
// family carries a unique id, so identity resolves and an unknown id refuses (null).
export const allergenFamilyStrategy = fieldStrategy("id");

// The cross-reactivity families (entries) the domain matcher consumes, in curated
// (source) order.
export const CROSS_REACTIVITY_FAMILIES: CrossReactivityFamily[] =
  allergenCrossReactivityDataset.entries;
